export const userRelations = relations(User, ({ one, many }) => ({
  assetsCreated: many(MediaAsset, {
    relationName: 'mediaAsset_createdById_user_id',
  }),
  createdOrganizations: many(Organization, {
    relationName: 'organization_createdById_user_id',
  }),
  systemOrganization: many(Organization, {
    relationName: 'organization_systemUserId_user_id',
  }),
  memberships: many(OrganizationMember),
  acceptedInvitations: many(OrganizationInvitation, {
    relationName: 'organizationInvitation_acceptedById_user_id',
  }),
  sentInvitations: many(OrganizationInvitation, {
    relationName: 'organizationInvitation_invitedById_user_id',
  }),
  userSettings: many(UserSetting),
  shopifyIntegrations: many(ShopifyIntegration),
  shopifyAuthStates: many(ShopifyAuthState),
  verificationTokens: many(VerificationToken),
  passwordResetTokens: many(PasswordResetToken),
  readStatuses: many(ThreadReadStatus),
  inboxUnreadCounts: many(UserInboxUnreadCount),
  messages: many(Message),
  threads: many(Thread),
  articles: many(Article),
  aiAgentSessions: many(AiAgentSession),
  aiUsages: many(AiUsage),
  aiIntegrations: many(AiIntegration),
  promptHistory: many(PromptHistory),
  ApiKey: many(ApiKey),
  articleRevisions: many(ArticleRevision),
  avatarAsset: one(MediaAsset, {
    fields: [User.avatarAssetId],
    references: [MediaAsset.id],
    relationName: 'user_avatarAssetId_mediaAsset_id',
  }),
  snippetFolders: many(SnippetFolder),
  snippets: many(Snippet),
  promptTemplates: many(PromptTemplate),
  comments: many(Comment, {
    relationName: 'comment_createdById_user_id',
  }),
  pinned: many(Comment, {
    relationName: 'comment_pinnedById_user_id',
  }),
  mentions: many(CommentMention),
  reactions: many(CommentReaction),
  mailViews: many(MailView),
  chatSessionsClosed: many(ChatSession),
  chatMessages: many(ChatMessage),
  triggeredNotifications: many(Notification, {
    relationName: 'notification_actorId_user_id',
  }),
  notifications: many(Notification, {
    relationName: 'notification_userId_user_id',
  }),
  passKeys: many(Passkey),
  accounts: many(account),
  sessions: many(session),
  twoFactor: many(TwoFactor),
  tableViews: many(TableView),
  searchHistory: many(SearchHistory),
  createdWorkflows: many(Workflow),
  createdWorkflowApps: many(WorkflowApp),
  workflowRuns: many(WorkflowRun),
  nodeExecutions: many(WorkflowNodeExecution),
  createdApprovals: many(ApprovalRequest),
  approvalResponses: many(ApprovalResponse),
  files: many(File, {
    relationName: 'file_createdById_user_id',
  }),
  deletedFiles: many(File, {
    relationName: 'file_deletedById_user_id',
  }),
  createdWorkflowCredentials: many(WorkflowCredentials),
  createdDatasets: many(Dataset),
  datasetSearchQueries: many(DatasetSearchQuery),
  createdExternalSources: many(ExternalKnowledgeSource),
  uploadedDocuments: many(Document),
  foldersCreated: many(Folder),
  attachments: many(Attachment),
  folderFilesCreated: many(FolderFile),
  endUsers: many(EndUser),
}))

